        q = '"' if value.startswith("'") and value.endswith("'") else "'"
        return "<{cls} {q}{value}{q} at 0x{id:2X}>".format(
            id=id(self), **locals())
    def _get_repr_name(self):
        return str(self.ttype).split('.')[-1]
    def _get_repr_value(self):
