            flag = re.IGNORECASE if self.is_keyword else 0
            values = (re.compile(v, flag) for v in values)
            for pattern in values:
                if pattern.search(self.normalized):
                    return True
            return False
        if self.is_keyword:
            values = (v.upper() for v in values)
